const loginGatePage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>LOGIN | BARE.</title>${loginGateStyle}</head><body><main class="login-shell"><nav class="login-top" aria-label="구매 로그인 이동"><button class="login-icon back-button" type="button" aria-label="이전으로"><svg viewBox="0 0 24 24"><path d="M15 18 9 12l6-6"/></svg></button><span></span><a class="login-icon home-link" href="/" aria-label="홈으로"><svg viewBox="0 0 24 24"><path d="m3 11 9-8 9 8"/><path d="M5 10v10h14V10"/><path d="M9 20v-6h6v6"/></svg></a></nav><div class="brand-mark"><img src="${logoUrl}" alt="BARE."></div><section aria-labelledby="login-title"><h1 id="login-title">로그인</h1><p class="intro">아이디와 비밀번호 입력하기 귀찮으시죠?<br>1초 회원가입으로 입력없이 간편하게 로그인 하세요.</p><button class="kakao-login social-login" type="button"><svg viewBox="0 0 24 24" aria-hidden="true"><path d="M12 4C6.49 4 2 7.54 2 11.9c0 2.83 1.9 5.3 4.75 6.7l-.82 3.02c-.12.45.38.82.77.56l3.58-2.38c.56.07 1.13.1 1.72.1 5.51 0 10-3.54 10-7.9S17.51 4 12 4Z"/></svg><span>카카오 1초 로그인/회원가입</span></button><p class="benefit-copy">카카오 1초 회원가입 시 베어닷 채널 추가 및<br>광고성 마케팅 수신 동의 고객에 한하여 혜택이 제공됩니다.</p><div class="benefits" aria-label="회원가입 혜택"><div class="benefit-card"><div class="benefit-num">01</div><div class="benefit-main">5,000원<br>쿠폰 증정</div></div><div class="benefit-card"><div class="benefit-num">02</div><div class="benefit-main">인기제품 7종<br>50% 할인</div><div class="benefit-sub">*7종 택1</div></div><div class="benefit-card"><div class="benefit-num">03</div><div class="benefit-main">금액대별<br>할인 쿠폰</div><div class="benefit-sub">*5만원 / 7만원 / 10만원</div></div></div><div class="divider">또는</div><div class="member-switch" role="tablist"><button class="is-active" type="button">기존 회원이세요?</button><button type="button">비회원 배송조회</button></div><form class="login-form"><label class="login-field"><input type="email" name="email" autocomplete="email" placeholder="이메일"></label><label class="login-field"><input type="password" name="password" autocomplete="current-password" placeholder="비밀번호"></label><button class="member-login" type="submit">기존 회원 로그인</button><button class="guest-buy" type="button">비회원 구매</button></form><div class="login-links"><div><button type="button" class="soft-action">아이디 찾기</button><span>|</span><button type="button" class="soft-action">비밀번호 찾기</button></div><button type="button" class="soft-action">회원가입</button></div><div class="divider">또는</div><button class="naver-login social-login" type="button" aria-label="네이버 로그인">N</button><p class="signup-copy">첫 구매가 빨라지는 <strong>1초 회원가입</strong> <span aria-hidden="true">⚡</span><br>살까 말까 고민하던 고객까지 막힘없이<small>i</small></p><p class="muted-copy">BARE.도 이미 1초 회원가입 사용 중</p></section></main><script>const checkoutUrl='/order/orderform.html?basket_type=A0000&delvtype=A';const params=new URLSearchParams(location.search);const returnUrl=params.get('returnUrl')||checkoutUrl;const readyMessage='카카오/네이버/회원 로그인은 실제 간편 로그인 키 연동 후 사용할 수 있어요. 지금은 비회원 구매로 결제까지 진행할 수 있습니다.';document.querySelector('.back-button')?.addEventListener('click',()=>{if(history.length>1)history.back();else location.href='/'});document.querySelector('.guest-buy')?.addEventListener('click',()=>{location.href=returnUrl});document.querySelector('.login-form')?.addEventListener('submit',event=>{event.preventDefault();alert(readyMessage)});document.querySelectorAll('.social-login,.soft-action,.member-switch button').forEach(btn=>btn.addEventListener('click',()=>{if(!btn.classList.contains('guest-buy'))alert(readyMessage)}));</script></body></html>`;
const checkoutPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ORDER | BARE.</title>${checkoutStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="checkout"><h1>ORDER FORM</h1><form class="checkout-grid" id="checkout-form"><section><div class="panel"><h2>배송지</h2><div class="tabs"><span>최근 배송지</span><span>직접입력</span></div><div class="row"><div class="field"><label for="buyer">주문자명</label><input id="buyer" name="buyer" autocomplete="name" required></div><div class="field"><label for="phone">연락처</label><input id="phone" name="phone" autocomplete="tel" required></div></div><div class="field"><label for="address">주소</label><input id="address" name="address" autocomplete="street-address" required></div><div class="field"><label for="memo">배송 메모</label><textarea id="memo" name="memo" placeholder="배송 요청사항을 입력해주세요"></textarea></div></div><div class="panel"><h2>할인/부가결제</h2><div class="summary-line"><span>자동 할인</span><strong>₩0</strong></div><div class="summary-line"><span>쿠폰 할인</span><strong>₩0</strong></div></div></section><aside><div class="panel"><h2>주문상품</h2><div class="order-list" id="order-list"></div></div><div class="panel"><h2>최종 결제 금액</h2><div class="summary-line"><span>주문상품</span><strong id="subtotal">₩0</strong></div><div class="summary-line"><span>배송비</span><strong id="shipping">₩3,500</strong></div><div class="summary-line total"><span>최종 결제금액</span><strong id="grand-total">₩0</strong></div></div><div class="panel"><h2>결제수단</h2><div class="payment-methods" role="radiogroup" aria-label="결제수단 선택"><label class="pay-option"><input type="radio" name="payMethod" value="CARD" checked> 카드/간편결제</label><label class="pay-option"><input type="radio" name="payMethod" value="TRANSFER"> 퀵계좌이체</label></div><p class="payment-window-note">선택한 결제수단에 맞춰 토스페이먼츠 결제창으로 이동합니다.</p><label class="agree"><input type="checkbox" required> 결제조건과 개인정보 수집 및 이용에 동의합니다.</label><button class="checkout-submit" type="submit">결제하기</button><p class="notice" id="checkout-notice">토스페이먼츠 결제창으로 결제를 진행합니다.</p></div></aside></form></main><script src="https://js.tosspayments.com/v2/standard"></script><script>const tossClientKey='live_ck_ZLKGPx4M3MqnNNYXJjko3BaWypv1';const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));const items=read('bare_checkout_items').length?read('bare_checkout_items'):read('bare_cart_items');const list=document.getElementById('order-list');const subtotal=items.reduce((sum,item)=>sum+Number(item.price||0),0);const shipping=items.length?3500:0;const grandTotal=subtotal+shipping;const submit=document.querySelector('.checkout-submit');const notice=document.getElementById('checkout-notice');if(!items.length){list.innerHTML='<p class="empty">주문할 상품이 없습니다.<br><a href="/">상품을 먼저 선택해주세요.</a></p>';submit.disabled=true}else{list.innerHTML=items.map(item=>'<article class="order-item"><img src="'+(item.image||'')+'" alt=""><div><p class="order-title">'+(item.title||'BARE. product')+'</p><p class="order-meta">'+(item.option||'옵션 선택 내역 없음')+'</p></div><strong class="price">'+money(item.price)+'</strong></article>').join('')}document.getElementById('subtotal').textContent=money(subtotal);document.getElementById('shipping').textContent=money(shipping);document.getElementById('grand-total').textContent=money(grandTotal);const customerKey=localStorage.getItem('bare_toss_customer_key')||('BARE_'+Date.now()+'_'+Math.random().toString(36).slice(2,10));localStorage.setItem('bare_toss_customer_key',customerKey);const tossPayments=TossPayments(tossClientKey);const payment=tossPayments.payment({customerKey});document.getElementById('checkout-form').addEventListener('submit',async event=>{event.preventDefault();if(!items.length)return;if(!event.currentTarget.reportValidity())return;const buyer=document.getElementById('buyer').value.trim();const phone=document.getElementById('phone').value.replace(/[^0-9]/g,'');const email=(document.getElementById('email-id')?.value&&document.getElementById('email-domain')?.value)?document.getElementById('email-id').value.trim()+'@'+document.getElementById('email-domain').value.trim():'';const address=document.getElementById('address').value.trim();const memo=document.getElementById('memo').value.trim();const orderId='BARE-'+Date.now()+'-'+Math.random().toString(36).slice(2,8).toUpperCase();const orderName=items.length>1?(items[0].title||'BARE. product')+' 외 '+(items.length-1)+'건':(items[0].title||'BARE. product');write('bare_pending_order',{orderId,items,amount:grandTotal,buyer,phone,email,address,memo,createdAt:Date.now()});write('bare_checkout_items',items);submit.disabled=true;notice.textContent='토스페이먼츠 결제창을 여는 중입니다.';const method=document.querySelector('input[name="payMethod"]:checked')?.value||'CARD';try{await payment.requestPayment({method,amount:{currency:'KRW',value:grandTotal},orderId,orderName,successUrl:location.origin+'/order/success',failUrl:location.origin+'/order/fail',customerName:buyer,customerMobilePhone:phone})}catch(error){submit.disabled=false;notice.textContent='토스페이먼츠 결제창으로 결제를 진행합니다.';if(error?.code==='USER_CANCEL')return;alert(error?.message||'결제를 시작하지 못했습니다.')}});</script></body></html>`;
const tossResultStyle=`<style>@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}*{box-sizing:border-box}body{margin:0;background:#050505;color:#fff;font-family:InterDisplay,Pretendard,'Noto Sans KR',system-ui,sans-serif}.checkout-top{height:76px;display:grid;place-items:center;background:#fff}.checkout-top img{width:70px;filter:brightness(0)}.result{width:min(620px,calc(100% - 36px));margin:0 auto;padding:90px 0 120px}.result h1{margin:0 0 16px;font-size:24px}.result p{margin:0 0 18px;color:#d8d8d8;font:800 13px/1.65 Pretendard,'Noto Sans KR',sans-serif}.result-box{display:grid;gap:10px;margin:22px 0;padding:18px;border-top:1px solid #444;border-bottom:1px solid #333}.result-line{display:flex;justify-content:space-between;gap:16px;color:#eee;font-size:12px}.result-actions{display:flex;flex-wrap:wrap;gap:8px;margin-top:24px}.result-actions a{display:inline-flex;align-items:center;justify-content:center;min-height:44px;padding:0 16px;background:#fff;color:#050505;text-decoration:none;font:900 12px/1 InterDisplay,Pretendard,sans-serif}.result-actions a.secondary{border:1px solid #444;background:#050505;color:#fff}.result-status{color:#aaa}@media(max-width:640px){.result{padding:58px 0 90px}.result-line{display:grid}}</style>`;
const tossSuccessPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>PAYMENT SUCCESS | BARE.</title>${tossResultStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="result"><h1>결제 확인 중</h1><p class="result-status" id="result-status">토스페이먼츠 승인 결과를 확인하고 있습니다.</p><div class="result-box" id="result-box"></div><div class="result-actions"><a href="/">SHOP으로 돌아가기</a><a class="secondary" href="/order/orderform.html?basket_type=A0000&delvtype=A">주문서로 돌아가기</a></div></main><script>const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));const params=new URLSearchParams(location.search);const paymentKey=params.get('paymentKey'),orderId=params.get('orderId'),amount=Number(params.get('amount')||0);const statusEl=document.getElementById('result-status'),box=document.getElementById('result-box');function draw(title,lines){document.querySelector('.result h1').textContent=title;box.innerHTML=lines.map(([label,value])=>'<div class="result-line"><span>'+label+'</span><strong>'+value+'</strong></div>').join('')}async function confirmPayment(){if(!paymentKey||!orderId||!amount){statusEl.textContent='결제 승인에 필요한 정보가 부족합니다.';draw('결제 확인 실패',[['주문번호',orderId||'-'],['결제금액',amount?money(amount):'-']]);return}const pending=read('bare_pending_order');if(!pending||pending.orderId!==orderId||Number(pending.amount)!==amount){statusEl.textContent='주문 정보와 결제 금액이 일치하지 않아 승인을 중단했습니다.';draw('결제 확인 실패',[['주문번호',orderId],['결제금액',money(amount)]]);return}try{const response=await fetch('/api/toss/confirm',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({paymentKey,orderId,amount,buyer:pending.buyer||'',phone:pending.phone||'',email:pending.email||'',address:pending.address||'',memo:pending.memo||'',items:pending.items||[]})});const data=await response.json();if(!response.ok)throw new Error(data.message||'결제 승인에 실패했습니다.');const orders=read('bare_order_items');const next=(pending.items||[]).map(item=>({...item,status:'결제 완료',paymentKey,orderId,createdAt:Date.now()}));write('bare_order_items',[...next,...orders].slice(0,30));localStorage.removeItem('bare_pending_order');localStorage.removeItem('bare_checkout_items');localStorage.removeItem('bare_checkout_draft');if(data.adminOrder?.saved===false)console.warn('Admin order save failed',data.adminOrder);statusEl.textContent='결제가 정상적으로 승인되었습니다. 주문이 접수되었습니다.';draw('결제 완료',[['주문번호',data.orderId||orderId],['결제금액',money(data.totalAmount||amount)],['결제수단',data.method||'-']])}catch(error){statusEl.textContent=error.message;draw('결제 승인 실패',[['주문번호',orderId],['결제금액',money(amount)]])}}confirmPayment();</script></body></html>`;
const tossFailPage=`<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>PAYMENT FAIL | BARE.</title>${tossResultStyle}</head><body><header class="checkout-top"><a href="/"><img src="${logoUrl}" alt="BARE."></a></header><main class="result"><h1>결제 실패</h1><p id="fail-message">결제가 완료되지 않았습니다.</p><div class="result-box" id="result-box"></div><div class="result-actions"><a href="/order/orderform.html?basket_type=A0000&delvtype=A">다시 결제하기</a><a class="secondary" href="/">SHOP으로 돌아가기</a></div></main><script>const params=new URLSearchParams(location.search);document.getElementById('fail-message').textContent=params.get('message')||'결제가 취소되었거나 실패했습니다.';document.getElementById('result-box').innerHTML='<div class="result-line"><span>에러코드</span><strong>'+(params.get('code')||'-')+'</strong></div><div class="result-line"><span>주문번호</span><strong>'+(params.get('orderId')||'-')+'</strong></div>';</script></body></html>`;
