const authScript=`<script type="module" id="bare-auth-review-script">import{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';const cfg=window.BARE_SUPABASE_CONFIG||{};const supabase=createClient(cfg.url,cfg.key);let user=null,mode='login';const modal=document.querySelector('.member-modal'),trigger=document.querySelector('.member-trigger'),form=document.querySelector('.member-form'),note=document.querySelector('.member-form .member-note'),userBox=document.querySelector('.member-user'),userNote=document.querySelector('.member-user .member-note'),logoutBtn=document.querySelector('.member-logout'),tabs=document.querySelectorAll('[data-member-mode]');function openModal(){modal?.classList.add('is-open');modal?.setAttribute('aria-hidden','false')}function closeModal(){modal?.classList.remove('is-open');modal?.setAttribute('aria-hidden','true')}function setNote(text){if(note)note.textContent=text}function syncUser(next){user=next;trigger&&(trigger.textContent=user?'ACCOUNT':'LOGIN');if(user){form&&(form.style.display='none');userBox?.classList.add('is-open');userNote&&(userNote.textContent=(user.email||'BARE. member')+' 로 로그인 중입니다.');window.dispatchEvent(new CustomEvent('bare-account-sync'))}else{form&&(form.style.display='grid');userBox?.classList.remove('is-open')}}trigger?.addEventListener('click',openModal);modal?.querySelector('.member-close')?.addEventListener('click',closeModal);modal?.addEventListener('click',e=>{if(e.target===modal)closeModal()});tabs.forEach(btn=>btn.addEventListener('click',()=>{if(btn.dataset.memberMode==='signup'){location.href='/member/signup.html';return}mode=btn.dataset.memberMode;tabs.forEach(item=>item.classList.toggle('is-active',item===btn));document.querySelector('.member-submit').textContent='LOGIN';setNote('이메일과 비밀번호로 로그인해주세요.')}));form?.addEventListener('submit',async e=>{e.preventDefault();const fd=new FormData(form),email=String(fd.get('email')||'').trim(),password=String(fd.get('password')||'');try{const result=mode==='signup'?await supabase.auth.signUp({email,password,options:{emailRedirectTo:location.origin}}):await supabase.auth.signInWithPassword({email,password});if(result.error)throw result.error;if(mode==='signup'&&!result.data.session){setNote('가입 메일을 보냈어요. 이메일 인증 후 로그인해주세요.');return}syncUser(result.data.user);closeModal()}catch(err){setNote(err.message||'회원 처리 중 문제가 생겼습니다.')}});logoutBtn?.addEventListener('click',async()=>{await supabase.auth.signOut();syncUser(null)});supabase.auth.onAuthStateChange((_event,session)=>syncUser(session?.user||null));const{data}=await supabase.auth.getUser();syncUser(data.user||null);</script>`;
const accountScript=`<script id="bare-account-panel-script">(()=>{const cartKey='bare_cart_items',orderKey='bare_order_items',checkoutKey='bare_checkout_items',checkoutUrl='/order/orderform.html?basket_type=A0000&delvtype=A',loginUrl='/member/login.html';const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));function goCheckout(items){write(checkoutKey,items.filter(Boolean));location.href=loginUrl+'?returnUrl='+encodeURIComponent(checkoutUrl)}function itemMarkup(item,index,kind){return '<article class="account-item"><img src="'+(item.image||'')+'" alt=""><div><p class="account-item-title">'+(item.title||'BARE. product')+'</p><p class="account-item-meta">'+(item.option||'옵션 선택 내역 없음')+'</p><p class="account-item-meta">'+new Date(item.createdAt||Date.now()).toLocaleDateString('ko-KR')+'</p></div><strong class="account-item-price">'+money(item.price)+'</strong>'+(kind==='cart'?'<button class="account-buy" type="button" data-cart-buy="'+index+'">BUY THIS ITEM</button>':'')+'</article>'}function ensureDashboard(){const box=document.querySelector('.member-user');if(!box||box.querySelector('.member-dashboard'))return;const note=box.querySelector('.member-note'),logout=box.querySelector('.member-logout');box.insertAdjacentHTML('afterbegin','<div class="member-dashboard"><div class="account-head"><div><p class="account-name"></p><p class="account-email"></p></div></div><div class="account-tabs"><button class="account-tab is-active" type="button" data-account-tab="orders">ORDER</button><button class="account-tab" type="button" data-account-tab="cart">CART</button></div><section class="account-panel is-active" data-account-panel="orders"><div class="account-list"></div></section><section class="account-panel" data-account-panel="cart"><div class="account-list"></div></section></div>');note?.remove();box.appendChild(logout);box.querySelectorAll('[data-account-tab]').forEach(btn=>btn.addEventListener('click',()=>{box.querySelectorAll('[data-account-tab]').forEach(tab=>tab.classList.toggle('is-active',tab===btn));box.querySelectorAll('[data-account-panel]').forEach(panel=>panel.classList.toggle('is-active',panel.dataset.accountPanel===btn.dataset.accountTab))}));box.addEventListener('click',event=>{const buy=event.target.closest('[data-cart-buy]');if(!buy)return;const item=read(cartKey)[Number(buy.dataset.cartBuy)];if(item)goCheckout([item])});renderAccount()}function renderAccount(){const box=document.querySelector('.member-user');if(!box)return;ensureDashboard();const name=(box.querySelector('.member-note')?.textContent||'').replace(' 로 로그인 중입니다.','')||'BARE. Member';box.querySelector('.account-name')&&(box.querySelector('.account-name').textContent=name);box.querySelector('.account-email')&&(box.querySelector('.account-email').textContent='비회원 구매도 로그인 없이 이용할 수 있습니다.');const orders=read(orderKey),cart=read(cartKey),orderList=box.querySelector('[data-account-panel="orders"] .account-list'),cartList=box.querySelector('[data-account-panel="cart"] .account-list');if(orderList)orderList.innerHTML=orders.length?orders.map((item,index)=>itemMarkup(item,index,'order')).join(''):'<p class="account-empty">아직 주문 내역이 없습니다.<br>스마트스토어 결제 완료 내역은 결제 연동 후 자동 표시됩니다.</p>';if(cartList)cartList.innerHTML=cart.length?cart.map((item,index)=>itemMarkup(item,index,'cart')).join(''):'<p class="account-empty">장바구니에 담긴 상품이 없습니다.<br>상품 상세에서 사이즈를 선택한 뒤 ADD TO CART를 눌러주세요.</p>'}function selectedOptionText(){return [...document.querySelectorAll('.option-block')].map(group=>{const label=group.querySelector('label')?.textContent?.trim()||'SIZE',size=group.querySelector('.size-button.is-selected')?.dataset.size;return size?label+': '+size:null}).filter(Boolean).join(' / ')}function detailItem(){if(typeof activeProduct==='undefined')return null;const option=selectedOptionText();if(!option)return null;return{title:activeProduct.title,price:typeof currentDetailPrice==='function'?currentDetailPrice():activeProduct.price,image:activeProduct.main,option,createdAt:Date.now()}}function ensureShopActions(){const total=document.querySelector('.total-row');if(!total||document.querySelector('.member-shop-actions'))return;total.insertAdjacentHTML('afterend','<div class="member-shop-actions"><button class="add-cart" type="button">ADD TO CART</button><button class="guest-buy" type="button">BUY NOW</button></div><p class="member-action-note">로그인하지 않아도 장바구니와 비회원 주문서를 사용할 수 있습니다.</p>');document.querySelector('.add-cart')?.addEventListener('click',()=>{const item=detailItem();if(!item){alert('사이즈를 먼저 선택해주세요.');return}const cart=read(cartKey);cart.unshift(item);write(cartKey,cart.slice(0,20));renderAccount();alert('장바구니에 담았습니다. ACCOUNT에서 확인할 수 있어요.')});document.querySelector('.guest-buy')?.addEventListener('click',()=>{const item=detailItem();if(!item){alert('사이즈를 먼저 선택해주세요.');return}goCheckout([item])})}document.addEventListener('click',event=>{if(event.target.closest('.member-trigger'))setTimeout(renderAccount,80);if(event.target.closest('.size-button'))setTimeout(ensureShopActions,80)});addEventListener('bare-account-sync',()=>setTimeout(renderAccount,80));addEventListener('hashchange',()=>setTimeout(ensureShopActions,120));ensureShopActions();renderAccount()})();</script>`;
const adminDashboardPage="<!doctype html>\n<html lang=\"ko\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>BARE. Admin</title>\n<style>\n@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}\n*{box-sizing:border-box}body{margin:0;background:#eef0f3;color:#1c2430;font-family:InterDisplay,\"Apple SD Gothic Neo\",Pretendard,\"Noto Sans KR\",system-ui,sans-serif}button,input,select,textarea{font:inherit}.admin{display:grid;grid-template-columns:220px minmax(0,1fr);min-height:100svh}.side{position:sticky;top:0;height:100svh;background:#111820;color:#fff;padding:22px 18px}.brand{display:flex;align-items:center;gap:10px;margin-bottom:30px}.brand img{width:42px;height:42px;filter:invert(1);opacity:.8}.brand strong{font-size:18px}.nav{display:grid;gap:8px}.nav button{width:100%;min-height:42px;border:0;border-radius:5px;background:transparent;color:#b9c1cb;text-align:left;padding:0 12px;font-weight:900;cursor:pointer}.nav button.is-active,.nav button:hover{background:#263241;color:#fff}.main{min-width:0;padding:26px}.top{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-bottom:20px}.top h1{margin:0;font-size:26px;line-height:1}.admin-actions{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.status{color:#6b7280;font:800 12px/1.5 Pretendard,\"Noto Sans KR\",sans-serif}.btn{min-height:36px;border:1px solid #111820;border-radius:4px;background:#111820;color:#fff;padding:0 12px;font-weight:900;cursor:pointer}.btn.secondary{background:#fff;color:#111820}.btn:disabled{opacity:.45;cursor:not-allowed}.login-card{width:min(460px,100%);margin:80px auto;padding:28px;background:#fff;border:1px solid #d7dce2;border-radius:6px}.login-card h2{margin:0 0 18px;font-size:22px}.field{display:grid;gap:7px;margin-bottom:12px}.field span{font:900 12px/1 Pretendard,\"Noto Sans KR\",sans-serif}.field input,.field select,.field textarea{width:100%;border:1px solid #cfd6df;border-radius:4px;background:#fff;padding:10px 11px;color:#111820}.field textarea{min-height:110px;resize:vertical}.cards{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:16px}.card{background:#fff;border:1px solid #dfe4ea;border-radius:6px;padding:16px}.card span{display:block;color:#6b7280;font:900 12px/1 Pretendard,\"Noto Sans KR\",sans-serif}.card strong{display:block;margin-top:10px;font-size:24px}.panel{display:none;background:#fff;border:1px solid #dfe4ea;border-radius:6px;overflow:hidden}.panel.is-active{display:block}.panel-head{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 16px;border-bottom:1px solid #e5e9ee}.panel-head h2{margin:0;font-size:16px}.filters{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.filters input,.filters select{height:34px;border:1px solid #cfd6df;border-radius:4px;padding:0 10px;background:#fff}.table-wrap{overflow:auto}.table{width:100%;border-collapse:collapse;min-width:940px}.table th,.table td{border-bottom:1px solid #edf0f3;padding:12px 14px;text-align:left;vertical-align:top;font:800 13px/1.45 Pretendard,\"Noto Sans KR\",sans-serif}.table th{background:#fafbfc;color:#5d6673;font-size:12px;white-space:nowrap}.table tr{cursor:pointer}.table tr:hover td{background:#f8fafc}.badge{display:inline-flex;align-items:center;min-height:24px;border-radius:999px;padding:0 9px;background:#eef2ff;color:#1d4ed8;font:900 11px/1 Pretendard,\"Noto Sans KR\",sans-serif;white-space:nowrap}.badge.ready{background:#fff7ed;color:#c2410c}.badge.shipping{background:#ecfdf5;color:#047857}.badge.done{background:#f3f4f6;color:#374151}.muted{color:#7a8492}.drawer{position:fixed;inset:0;z-index:50;display:none;background:rgba(15,23,42,.42)}.drawer.is-open{display:block}.drawer-panel{position:absolute;top:0;right:0;width:min(620px,100%);height:100%;overflow:auto;background:#fff;box-shadow:-18px 0 48px rgba(0,0,0,.2)}.drawer-head{position:sticky;top:0;z-index:1;display:flex;align-items:center;justify-content:space-between;gap:14px;padding:18px;border-bottom:1px solid #e5e9ee;background:#fff}.drawer-head h2{margin:0;font-size:18px}.drawer-body{padding:18px}.detail-grid{display:grid;grid-template-columns:120px minmax(0,1fr);gap:10px 14px;margin-bottom:18px}.detail-grid span{color:#6b7280;font-weight:900}.detail-grid strong{word-break:break-word}.items{display:grid;gap:8px;margin:10px 0 20px}.item{display:grid;grid-template-columns:54px minmax(0,1fr) auto;gap:10px;align-items:center;border:1px solid #e5e9ee;border-radius:5px;padding:8px}.item img{width:54px;height:64px;object-fit:cover;background:#eee}.item p{margin:0}.item small{display:block;margin-top:4px;color:#7a8492}.notice{margin:12px 0 0;color:#6b7280;font:800 12px/1.55 Pretendard,\"Noto Sans KR\",sans-serif}.empty{padding:34px 16px;color:#7a8492;text-align:center;font-weight:900}.qna-form{display:grid;gap:10px;margin-top:18px}.hidden{display:none!important}@media(max-width:960px){.admin{grid-template-columns:1fr}.side{position:static;height:auto}.nav{grid-template-columns:repeat(3,minmax(0,1fr))}.main{padding:18px}.cards{grid-template-columns:repeat(2,minmax(0,1fr))}.top{align-items:flex-start;flex-direction:column}.table{min-width:820px}}@media(max-width:560px){.cards{grid-template-columns:1fr}.nav{grid-template-columns:1fr}.main{padding:14px}.login-card{margin:26px auto}.drawer-panel{width:100%}}\n</style>\n</head>\n<body>\n<main class=\"admin\">\n<aside class=\"side\">\n  <div class=\"brand\"><img src=\"https://framerusercontent.com/images/a3Pvzk5vHkS6uAT6JGV5VgPpTZk.png?width=1080&height=1080\" alt=\"\"><strong>BARE. ADMIN</strong></div>\n  <nav class=\"nav\" aria-label=\"관리 메뉴\">\n    <button class=\"is-active\" type=\"button\" data-tab=\"orders\">주문관리</button>\n    <button type=\"button\" data-tab=\"qna\">Q&A</button>\n    <button type=\"button\" data-tab=\"settings\">설정</button>\n  </nav>\n</aside>\n<section class=\"main\">\n  <div class=\"top\">\n    <div><h1>쇼핑몰 관리자</h1><p class=\"status\" id=\"status\">관리자 로그인을 확인하고 있습니다.</p></div>\n    <div class=\"admin-actions\"><a class=\"btn secondary\" href=\"/\">사이트 보기</a><button class=\"btn secondary\" type=\"button\" id=\"refresh\">새로고침</button><button class=\"btn\" type=\"button\" id=\"logout\">로그아웃</button></div>\n  </div>\n  <section class=\"login-card\" id=\"login-card\">\n    <h2>관리자 로그인</h2>\n    <label class=\"field\"><span>이메일</span><input id=\"email\" type=\"email\" autocomplete=\"email\"></label>\n    <label class=\"field\"><span>비밀번호</span><input id=\"password\" type=\"password\" autocomplete=\"current-password\"></label>\n    <button class=\"btn\" type=\"button\" id=\"login\">로그인</button>\n    <p class=\"notice\">Supabase 계정으로 로그인합니다. 관리자 이메일은 Cloudflare `ADMIN_EMAILS`에 등록되어 있어야 합니다.</p>\n  </section>\n  <section id=\"dashboard\" class=\"hidden\">\n    <div class=\"cards\">\n      <article class=\"card\"><span>전체 주문</span><strong id=\"metric-orders\">0</strong></article>\n      <article class=\"card\"><span>총 결제금액</span><strong id=\"metric-sales\">₩0</strong></article>\n      <article class=\"card\"><span>배송 준비</span><strong id=\"metric-ready\">0</strong></article>\n      <article class=\"card\"><span>미답변 문의</span><strong id=\"metric-qna\">0</strong></article>\n    </div>\n    <section class=\"panel is-active\" data-panel=\"orders\">\n      <div class=\"panel-head\"><h2>주문 목록</h2><div class=\"filters\"><input id=\"order-search\" placeholder=\"주문번호/이름/연락처\"><select id=\"order-status\"><option value=\"\">전체 상태</option><option value=\"paid\">결제완료</option><option value=\"ready\">상품준비중</option><option value=\"shipping\">배송중</option><option value=\"done\">배송완료</option></select></div></div>\n      <div class=\"table-wrap\"><table class=\"table\"><thead><tr><th>주문일</th><th>주문번호</th><th>주문자</th><th>상품</th><th>결제금액</th><th>결제</th><th>배송상태</th></tr></thead><tbody id=\"orders-body\"></tbody></table></div>\n    </section>\n    <section class=\"panel\" data-panel=\"qna\">\n      <div class=\"panel-head\"><h2>Q&A 목록</h2><div class=\"filters\"><input id=\"qna-search\" placeholder=\"이름/연락처/내용\"><select id=\"qna-status\"><option value=\"\">전체 상태</option><option value=\"new\">미답변</option><option value=\"answered\">답변완료</option><option value=\"closed\">종료</option></select></div></div>\n      <div class=\"table-wrap\"><table class=\"table\"><thead><tr><th>접수일</th><th>상태</th><th>이름</th><th>연락처</th><th>분류</th><th>내용</th></tr></thead><tbody id=\"qna-body\"></tbody></table></div>\n    </section>\n    <section class=\"panel\" data-panel=\"settings\">\n      <div class=\"panel-head\"><h2>설정 체크리스트</h2></div>\n      <div class=\"drawer-body\"><p class=\"notice\">1. Supabase SQL Editor에서 `supabase-admin-schema.sql` 실행</p><p class=\"notice\">2. Cloudflare 환경변수 `SUPABASE_URL`, `SUPABASE_SERVICE_ROLE_KEY`, `ADMIN_EMAILS`, `TOSS_SECRET_KEY` 설정</p><p class=\"notice\">3. Supabase Auth에 관리자 계정 생성 후 `ADMIN_EMAILS`에 이메일 등록</p></div>\n    </section>\n  </section>\n</section>\n</main>\n<aside class=\"drawer\" id=\"drawer\" aria-hidden=\"true\"><div class=\"drawer-panel\"><div class=\"drawer-head\"><h2 id=\"drawer-title\">상세</h2><button class=\"btn secondary\" type=\"button\" id=\"drawer-close\">닫기</button></div><div class=\"drawer-body\" id=\"drawer-body\"></div></div></aside>\n<script type=\"module\">\nimport{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';\nconst supabase=createClient('https://adltmckypuqwzbcuvuuh.supabase.co','sb_publishable_ZDEvoNTASICy-Z2hqqTOGA_EHFz2Yv1');\nconst money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');\nconst date=value=>value?new Date(value).toLocaleString('ko-KR'):'-';\nconst statusLabel={paid:'결제완료',ready:'상품준비중',shipping:'배송중',done:'배송완료',new:'미답변',answered:'답변완료',closed:'종료'};\nconst els={status:document.querySelector('#status'),loginCard:document.querySelector('#login-card'),dashboard:document.querySelector('#dashboard'),ordersBody:document.querySelector('#orders-body'),qnaBody:document.querySelector('#qna-body'),drawer:document.querySelector('#drawer'),drawerTitle:document.querySelector('#drawer-title'),drawerBody:document.querySelector('#drawer-body')};\nlet session=null,orders=[],inquiries=[];\nfunction setStatus(text){els.status.textContent=text}\nfunction token(){return session?.access_token||''}\nasync function api(path,options={}){const response=await fetch(path,{...options,headers:{'Content-Type':'application/json',Authorization:'Bearer '+token(),...(options.headers||{})}});const data=await response.json().catch(()=>({}));if(!response.ok)throw new Error(data.message||'요청을 처리하지 못했습니다.');return data}\nfunction showApp(visible){els.loginCard.classList.toggle('hidden',visible);els.dashboard.classList.toggle('hidden',!visible)}\nasync function loadAll(){setStatus('주문과 문의를 불러오는 중입니다.');const data=await api('/api/admin/summary');orders=data.orders||[];inquiries=data.inquiries||[];renderMetrics();renderOrders();renderQna();setStatus((session.user.email||'관리자')+' 계정으로 로그인했습니다.')}\nfunction renderMetrics(){document.querySelector('#metric-orders').textContent=orders.length;document.querySelector('#metric-sales').textContent=money(orders.reduce((sum,item)=>sum+Number(item.amount||0),0));document.querySelector('#metric-ready').textContent=orders.filter(item=>['paid','ready'].includes(item.fulfillment_status)).length;document.querySelector('#metric-qna').textContent=inquiries.filter(item=>item.status==='new').length}\nfunction orderProducts(order){return (order.items||[]).map(item=>item.product_title).join(', ')||'-'}\nfunction renderOrders(){const term=document.querySelector('#order-search').value.trim().toLowerCase(),filter=document.querySelector('#order-status').value;const rows=orders.filter(order=>(!filter||order.fulfillment_status===filter)&&[order.order_id,order.buyer_name,order.phone,order.address,orderProducts(order)].join(' ').toLowerCase().includes(term));els.ordersBody.innerHTML=rows.map(order=>'<tr data-order=\"'+order.order_id+'\"><td>'+date(order.created_at)+'</td><td>'+order.order_id+'</td><td>'+(order.buyer_name||'-')+'<br><span class=\"muted\">'+(order.phone||'')+'</span></td><td>'+orderProducts(order)+'</td><td>'+money(order.amount)+'</td><td><span class=\"badge\">'+(statusLabel[order.payment_status]||order.payment_status||'-')+'</span></td><td><span class=\"badge '+(order.fulfillment_status||'')+'\">'+(statusLabel[order.fulfillment_status]||order.fulfillment_status||'-')+'</span></td></tr>').join('')||'<tr><td colspan=\"7\" class=\"empty\">주문이 없습니다.</td></tr>'}\nfunction renderQna(){const term=document.querySelector('#qna-search').value.trim().toLowerCase(),filter=document.querySelector('#qna-status').value;const rows=inquiries.filter(item=>(!filter||item.status===filter)&&[item.name,item.phone,item.email,item.category,item.message].join(' ').toLowerCase().includes(term));els.qnaBody.innerHTML=rows.map(item=>'<tr data-inquiry=\"'+item.id+'\"><td>'+date(item.created_at)+'</td><td><span class=\"badge '+(item.status||'')+'\">'+(statusLabel[item.status]||item.status||'-')+'</span></td><td>'+(item.name||'-')+'</td><td>'+(item.phone||item.email||'-')+'</td><td>'+(item.category||'-')+'</td><td>'+String(item.message||'').slice(0,80)+'</td></tr>').join('')||'<tr><td colspan=\"6\" class=\"empty\">문의가 없습니다.</td></tr>'}\nfunction openDrawer(title,html){els.drawerTitle.textContent=title;els.drawerBody.innerHTML=html;els.drawer.classList.add('is-open');els.drawer.setAttribute('aria-hidden','false')}\nfunction closeDrawer(){els.drawer.classList.remove('is-open');els.drawer.setAttribute('aria-hidden','true')}\nfunction orderDetail(order){openDrawer('주문 상세',`<div class=\"detail-grid\"><span>주문번호</span><strong>${order.order_id}</strong><span>주문자</span><strong>${order.buyer_name||'-'}</strong><span>연락처</span><strong>${order.phone||'-'}</strong><span>주소</span><strong>${order.address||'-'}</strong><span>메모</span><strong>${order.memo||'-'}</strong><span>결제금액</span><strong>${money(order.amount)}</strong><span>결제수단</span><strong>${order.payment_method||'-'}</strong><span>paymentKey</span><strong>${order.payment_key||'-'}</strong></div><h3>상품</h3><div class=\"items\">${(order.items||[]).map(item=>`<article class=\"item\"><img src=\"${item.image_url||''}\" alt=\"\"><div><p>${item.product_title}</p><small>${item.option_text||''}</small></div><strong>${money(item.price)}</strong></article>`).join('')}</div><label class=\"field\"><span>배송상태</span><select id=\"detail-status\"><option value=\"paid\">결제완료</option><option value=\"ready\">상품준비중</option><option value=\"shipping\">배송중</option><option value=\"done\">배송완료</option></select></label><button class=\"btn\" type=\"button\" id=\"save-order\">상태 저장</button>`);document.querySelector('#detail-status').value=order.fulfillment_status||'paid';document.querySelector('#save-order').addEventListener('click',async()=>{await api('/api/admin/orders/'+encodeURIComponent(order.order_id),{method:'PATCH',body:JSON.stringify({fulfillment_status:document.querySelector('#detail-status').value})});closeDrawer();await loadAll()})}\nfunction qnaDetail(item){openDrawer('Q&A 상세',`<div class=\"detail-grid\"><span>접수일</span><strong>${date(item.created_at)}</strong><span>이름</span><strong>${item.name||'-'}</strong><span>연락처</span><strong>${item.phone||'-'}</strong><span>이메일</span><strong>${item.email||'-'}</strong><span>분류</span><strong>${item.category||'-'}</strong><span>문의</span><strong>${item.message||'-'}</strong></div><div class=\"qna-form\"><label class=\"field\"><span>상태</span><select id=\"qna-detail-status\"><option value=\"new\">미답변</option><option value=\"answered\">답변완료</option><option value=\"closed\">종료</option></select></label><label class=\"field\"><span>관리자 답변/메모</span><textarea id=\"qna-reply\">${item.admin_reply||''}</textarea></label><button class=\"btn\" type=\"button\" id=\"save-qna\">저장</button></div>`);document.querySelector('#qna-detail-status').value=item.status||'new';document.querySelector('#save-qna').addEventListener('click',async()=>{await api('/api/admin/inquiries/'+encodeURIComponent(item.id),{method:'PATCH',body:JSON.stringify({status:document.querySelector('#qna-detail-status').value,admin_reply:document.querySelector('#qna-reply').value})});closeDrawer();await loadAll()})}\ndocument.querySelector('#login').addEventListener('click',async()=>{setStatus('로그인 중입니다.');const{data,error}=await supabase.auth.signInWithPassword({email:document.querySelector('#email').value.trim(),password:document.querySelector('#password').value});if(error){setStatus(error.message);return}session=data.session;showApp(true);await loadAll()});\ndocument.querySelector('#logout').addEventListener('click',async()=>{await supabase.auth.signOut();session=null;showApp(false);setStatus('로그아웃했습니다.')});\ndocument.querySelector('#refresh').addEventListener('click',()=>session&&loadAll());\ndocument.querySelectorAll('[data-tab]').forEach(button=>button.addEventListener('click',()=>{document.querySelectorAll('[data-tab]').forEach(item=>item.classList.toggle('is-active',item===button));document.querySelectorAll('[data-panel]').forEach(panel=>panel.classList.toggle('is-active',panel.dataset.panel===button.dataset.tab))}));\ndocument.querySelector('#order-search').addEventListener('input',renderOrders);document.querySelector('#order-status').addEventListener('change',renderOrders);document.querySelector('#qna-search').addEventListener('input',renderQna);document.querySelector('#qna-status').addEventListener('change',renderQna);\nels.ordersBody.addEventListener('click',event=>{const row=event.target.closest('[data-order]');if(row){const order=orders.find(item=>item.order_id===row.dataset.order);if(order)orderDetail(order)}});els.qnaBody.addEventListener('click',event=>{const row=event.target.closest('[data-inquiry]');if(row){const item=inquiries.find(entry=>entry.id===row.dataset.inquiry);if(item)qnaDetail(item)}});\ndocument.querySelector('#drawer-close').addEventListener('click',closeDrawer);els.drawer.addEventListener('click',event=>{if(event.target===els.drawer)closeDrawer()});\nsupabase.auth.getSession().then(async({data})=>{session=data.session;if(session){showApp(true);await loadAll()}else{showApp(false);setStatus('관리자 계정으로 로그인해주세요.')}}).catch(error=>setStatus(error.message));\n</script>\n</body>\n</html>\n";
const qnaInquiryPage="<!doctype html>\n<html lang=\"ko\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Q&A | BARE.</title>\n<style>\n@font-face{font-family:InterDisplay;src:url(https://framerusercontent.com/assets/qITWJ2WdG0wrgQPDb8lvnYnTXDg.woff2) format('woff2');font-weight:700;font-display:swap}\n*{box-sizing:border-box}body{margin:0;background:#fff;color:#050505;font-family:InterDisplay,\"Apple SD Gothic Neo\",Pretendard,\"Noto Sans KR\",system-ui,sans-serif}.wrap{width:min(720px,calc(100% - 36px));margin:0 auto;padding:44px 0 80px}.top{display:flex;align-items:center;justify-content:space-between;margin-bottom:56px}.brand img{width:64px;filter:brightness(0)}.home{color:#050505;text-decoration:none;font:900 12px/1 InterDisplay,sans-serif;text-transform:uppercase}h1{margin:0 0 14px;font-size:clamp(34px,5vw,58px);line-height:.95;text-transform:uppercase}p{margin:0 0 28px;color:#555;font:800 14px/1.65 Pretendard,\"Noto Sans KR\",sans-serif}.form{display:grid;gap:14px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.field{display:grid;gap:7px}.field span{font:900 12px/1 Pretendard,\"Noto Sans KR\",sans-serif}.field input,.field select,.field textarea{width:100%;border:1px solid #d6d6d6;background:#fff;color:#050505;padding:13px;font:800 14px/1.5 Pretendard,\"Noto Sans KR\",sans-serif}.field textarea{min-height:180px;resize:vertical}.submit{min-height:52px;border:0;background:#050505;color:#fff;font:900 15px/1 Pretendard,\"Noto Sans KR\",sans-serif;cursor:pointer}.submit:disabled{opacity:.55;cursor:wait}.status{min-height:22px;color:#555;font:800 13px/1.5 Pretendard,\"Noto Sans KR\",sans-serif}@media(max-width:640px){.grid{grid-template-columns:1fr}.wrap{padding-top:28px}.top{margin-bottom:42px}}\n</style>\n</head>\n<body>\n<main class=\"wrap\">\n<header class=\"top\"><a class=\"brand\" href=\"/\" aria-label=\"BARE. home\"><img src=\"https://framerusercontent.com/images/a3Pvzk5vHkS6uAT6JGV5VgPpTZk.png?width=1080&height=1080\" alt=\"BARE.\"></a><a class=\"home\" href=\"/\">Back to shop</a></header>\n<h1>Q&A</h1>\n<p>주문, 배송, 제품 문의를 남겨주세요. 관리자 페이지에서 확인 후 답변드릴게요.</p>\n<form class=\"form\" id=\"qna-form\">\n  <div class=\"grid\"><label class=\"field\"><span>이름</span><input name=\"name\" autocomplete=\"name\"></label><label class=\"field\"><span>연락처</span><input name=\"phone\" autocomplete=\"tel\"></label></div>\n  <div class=\"grid\"><label class=\"field\"><span>이메일</span><input name=\"email\" type=\"email\" autocomplete=\"email\"></label><label class=\"field\"><span>분류</span><select name=\"category\"><option>상품 문의</option><option>주문/결제</option><option>배송</option><option>교환/반품</option><option>기타</option></select></label></div>\n  <label class=\"field\"><span>문의 내용</span><textarea name=\"message\" required placeholder=\"문의 내용을 입력해주세요.\"></textarea></label>\n  <button class=\"submit\" type=\"submit\">문의 남기기</button>\n  <div class=\"status\" id=\"status\" aria-live=\"polite\"></div>\n</form>\n</main>\n<script>\nconst form=document.getElementById('qna-form'),status=document.getElementById('status'),submit=form.querySelector('.submit');\nform.addEventListener('submit',async event=>{event.preventDefault();const data=Object.fromEntries(new FormData(form));submit.disabled=true;status.textContent='문의를 저장하고 있습니다.';try{const response=await fetch('/api/inquiries',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});const result=await response.json();if(!response.ok)throw new Error(result.message||'문의 저장에 실패했습니다.');form.reset();status.textContent='문의가 접수되었습니다.'}catch(error){status.textContent=error.message}finally{submit.disabled=false}});\n</script>\n</body>\n</html>\n";

function patchHtml(html){const headerPattern=/<header class="topbar" aria-label="BAREDOT navigation">[\s\S]*?<\/header>/;let patched=html.replace('<meta name="viewport" content="width=device-width, initial-scale=1">','<meta name="viewport" content="width=device-width, initial-scale=1">'+bareIntroHeadScript).replace(/<section class="hero"[\s\S]*?<\/section>/,'<section class="hero" aria-label="BARE. hero video"><video class="hero-video" autoplay muted loop playsinline webkit-playsinline preload="auto"><source src="assets/hero-comp-1-21.mp4" type="video/mp4"></video></section>').replace(/<script>function ensureHeroVideo\(\)[\s\S]*?<\/script>/,'').replace(/<style id="fix-hero-full-final">[\s\S]*?<\/style>/g,'').replace(/<style id="fix-mens-soon-final">[\s\S]*?<\/style>/g,'').replace(/<script id="fix-mens-soon-typing">[\s\S]*?<\/script>/g,'').replace(/\.collection-empty\.is-visible\{animation:men-soon-type-short 3\.4s steps\(5,end\) infinite!important\}@keyframes men-soon-type-short\{0%,12%\{width:0\}48%,72%\{width:5ch\}100%\{width:0\}\}/g,'').replace(/assets\/hero-original-web\.mp4/g,'assets/hero-comp-1-21.mp4').replace(/<style id="codex-deploy-menu-promo">[\s\S]*?<\/style>/,'').replace(/<style id="bare-auth-review-style">[\s\S]*?<\/style>/,'').replace(/<script id="bare-account-panel-script">[\s\S]*?<\/script>/,'').replace(/<script id="bare-firebase-config">[\s\S]*?<\/script>/,'').replace(/<script id="bare-supabase-config">[\s\S]*?<\/script>/,'').replace(/<script type="module" id="bare-auth-review-script">[\s\S]*?<\/script>/,'').replace(/<aside class="member-modal"[\s\S]*?<\/aside>/,'');patched=patched.replace('</head>',menuStyle+'\n'+authStyle+'\n'+mensSoonStyle+'\n'+bareBuyInstructorStyle+'\n'+detailBuyBarStyle+'\n'+heroFullStyle+'\n'+sandollFontStyle+'\n</head>');patched=patched.replace(headerPattern,menuHeader);patched=patched.replace(/<nav class="footer-links" aria-label="Footer information">[\s\S]*?<\/nav>/,footerLinks);return patched.replace('</body>',memberMarkup+'\n'+supabaseConfig+'\n'+authScript+'\n'+accountScript+'\n'+mensSoonScript+'\n'+instructorMarkup+'\n'+bareBuyInstructorScript+'\n</body>')}
export default{async fetch(request,env){const url=new URL(request.url);if(url.pathname==='/api/phone/send')return sendPhoneOtp(request,env);if(url.pathname==='/api/phone/verify')return verifyPhoneOtp(request,env);if(url.pathname==='/api/toss/confirm')return confirmTossPayment(request,env);if(url.pathname.startsWith('/api/products/slug/'))return publicProductApi(env,url);if(url.pathname.startsWith('/api/admin/'))return adminApi(request,env,url);if(url.pathname==='/api/inquiries')return createInquiry(request,env);if(url.pathname==='/api/auth/kakao')return startSocialAuth(request,env,'kakao');if(url.pathname==='/api/auth/naver')return startSocialAuth(request,env,'naver');if(url.pathname==='/api/auth/kakao/callback')return handleSocialCallback(request,env,'kakao');if(url.pathname==='/api/auth/naver/callback')return handleSocialCallback(request,env,'naver');if(url.pathname==='/admin/orders')return new Response(adminOrdersPage(env),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/admin/products')return new Response(adminProductsPage(env),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/q-and-a.html'||url.pathname==='/q-and-a')return new Response(qnaPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/my-page'||url.pathname==='/mypage'||url.pathname==='/myshop/index.html')return new Response(myPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/about.html'||url.pathname==='/about')return new Response(aboutPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/member/login.html'||url.pathname==='/member/login'||url.pathname==='/login')return new Response(simpleLoginPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/member/signup.html'||url.pathname==='/member/signup'||url.pathname==='/signup')return new Response(signupPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/orderform.html'||url.pathname==='/order/orderform')return new Response(modernCheckoutPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/success')return new Response(tossSuccessPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/fail')return new Response(tossFailPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/admin.html'||url.pathname==='/admin')return new Response(adminDashboardPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/qna.html'||url.pathname==='/qna')return new Response(qnaInquiryPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});const response=await env.ASSETS.fetch(request);const type=response.headers.get('content-type')||'';if(!type.includes('text/html'))return response;const headers=new Headers(response.headers);headers.delete('content-length');headers.set('cache-control','no-cache');return new Response(patchHtml(await response.text()),{status:response.status,statusText:response.statusText,headers})}};

