async function publicProductApi(env,url){
  try{
    const slug=decodeURIComponent(url.pathname.replace('/api/products/slug/','')).trim();
    if(!slug)return jsonResponse({message:'slug가 필요합니다.'},400);
    const rows=await supabaseRest(env,'products?select=slug,name,category,status,price,compare_price,stock,description,sizes,colors,tags,images,variants&slug=eq.'+encodeURIComponent(slug)+'&limit=1');
    const product=Array.isArray(rows)?rows[0]:null;
    if(!product)return jsonResponse({message:'상품을 찾을 수 없습니다.'},404);
    return jsonResponse({
      slug:product.slug,
      name:product.name,
      category:product.category,
      status:product.status,
      price:Number(product.price||0),
      compare_price:Number(product.compare_price||0),
      stock:Number(product.stock||0),
      description:product.description||'',
      sizes:Array.isArray(product.sizes)?product.sizes:[],
      colors:Array.isArray(product.colors)?product.colors:[],
      tags:Array.isArray(product.tags)?product.tags:[],
      images:Array.isArray(product.images)?product.images:[],
      variants:normalizeProductVariants(product.variants||[]).map(item=>({id:item.id,color:item.color,back:item.back,size:item.size,stock:item.stock,soldout:item.soldout,active:item.active}))
    });
  }catch(error){
    return jsonResponse({message:error.message||'상품 재고를 불러오지 못했습니다.',variants:[]},200);
  }
}

const productStockSyncScript=`<script id="bare-product-stock-sync">(()=>{const menHash='#product-t-libbed-sleeveless',slug='t-libbed-sleeveless',groups=['color','back','size'],money=value=>'₩'+Number(value||0).toLocaleString('ko-KR'),escapeHtml=value=>String(value??'').replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));let liveVariants=null,liveProduct=null,loaded=false;const selected=group=>document.querySelector('.option-block[data-option-group="'+group+'"] .size-button.is-selected')?.dataset.value||'';const current=()=>({color:selected('color'),back:selected('back'),size:selected('size')});const isMen=()=>location.hash===menHash;const match=(variant,selection)=>groups.every(group=>!selection[group]||String(variant[group]||'')===selection[group]);const usable=()=>Array.isArray(liveVariants)?liveVariants.filter(variant=>variant.active!==false&&!variant.soldout&&Number(variant.stock||0)>0):null;function selectionAvailable(selection){const variants=usable();if(!variants)return true;return variants.some(variant=>match(variant,selection))}function selectedVariant(selection){const variants=usable();if(!variants)return null;return variants.find(variant=>match(variant,selection))||null}function zeroTotal(){document.querySelector('#set-qty')&&(document.querySelector('#set-qty').textContent='0');document.querySelector('#set-total')&&(document.querySelector('#set-total').textContent='0')}function syncMenTotal(){const selection=current();if(!groups.every(group=>selection[group])){zeroTotal();return false}const variant=selectedVariant(selection);if(!variant){zeroTotal();return false}const price=Number(liveProduct?.price||variant.price||0);document.querySelector('#set-qty')&&(document.querySelector('#set-qty').textContent='1');document.querySelector('#set-total')&&(document.querySelector('#set-total').textContent=money(price));return true}function updateText(){if(!liveProduct)return;const name=liveProduct.name||'T-libbed sleeveless',price=Number(liveProduct.price||0);document.querySelectorAll('h1,h2,.product-title,.product-name,.detail-title,.purchase-panel strong,.purchase-panel h1,.purchase-panel h2').forEach(el=>{const text=(el.textContent||'').trim();if(/T[- ]?LIBBED|T-libbed|sleeveless/i.test(text)&&!/[₩￦]/.test(text))el.textContent=/^[A-Z0-9\\\\-\\\\s]+$/.test(text)?name.toUpperCase():name});if(price){document.querySelectorAll('.product-detail *,.purchase-panel *,.product-card *').forEach(el=>{if(el.children.length)return;const text=(el.textContent||'').trim();if(/[₩￦]?\\s*29,900/.test(text)||text==='29900')el.textContent=money(price)})}}function updateImages(){if(!liveProduct)return;const images=Array.isArray(liveProduct.images)?liveProduct.images.filter(img=>img&&img.url):[];if(!images.length)return;const urls=images.map(img=>img.url),main=urls[0];if(typeof activeProduct==='object'&&activeProduct){activeProduct.title=liveProduct.name||activeProduct.title;activeProduct.price=Number(liveProduct.price||activeProduct.price||0);activeProduct.main=main;activeProduct.detail=urls}document.querySelectorAll('.product-card img,.product-summary img,.product-top img,.purchase-panel img').forEach(img=>{const src=img.getAttribute('src')||'';if(/t-libbed|sleeveless|t-libbed-detail/.test(src))img.src=main});const detail=document.querySelector('.detail-images');if(detail){detail.innerHTML=images.map((img,index)=>'<img src="'+escapeHtml(img.url)+'" alt="'+escapeHtml((liveProduct.name||'BARE. product')+' '+(index+1))+'" style="margin-bottom:'+Math.max(0,Number(img.gap||0)||0)+'px">').join('')}}function applyProduct(){updateText();updateImages();document.dispatchEvent(new CustomEvent('bare-product-updated',{detail:liveProduct}))}function renderDynamicOptions(){if(!isMen()||!Array.isArray(liveVariants))return;const options=document.querySelector('.product-options'),source=liveVariants.filter(variant=>variant.active!==false);if(!options||!source.length)return;const labels={color:'COLOR',back:'BACK',size:'SIZE'};options.innerHTML=groups.map(group=>{const values=[...new Set(source.map(variant=>String(variant[group]||'').trim()).filter(Boolean))];return '<div class="option-block men-option-block" data-option-group="'+group+'"><label>'+labels[group]+'</label><div class="size-buttons" role="radiogroup" aria-label="'+labels[group]+' 선택">'+values.map(value=>'<button class="size-button is-dynamic-option" type="button" data-value="'+escapeHtml(value)+'" data-size="'+escapeHtml(value)+'">'+escapeHtml(value)+'</button>').join('')+'</div><span class="option-help">[필수] '+labels[group]+' 선택</span></div>'}).join('');options.querySelectorAll('.men-option-block .size-button').forEach(optionButton=>optionButton.addEventListener('click',event=>{event.preventDefault();event.stopImmediatePropagation();if(optionButton.disabled||optionButton.classList.contains('is-stock-soldout')){applyStock();return}const block=optionButton.closest('.option-block'),wasSelected=optionButton.classList.contains('is-selected');block?.querySelectorAll('.size-button').forEach(button=>button.classList.toggle('is-selected',!wasSelected&&button===optionButton));applyStock();syncMenTotal()},true))}function applyStock(){if(!isMen())return;const variants=usable();if(!variants)return;const selection=current();groups.forEach(group=>{document.querySelectorAll('.option-block[data-option-group="'+group+'"] .size-button[data-value]').forEach(button=>{const test={...selection,[group]:button.dataset.value};const enabled=selectionAvailable(test);button.disabled=!enabled;button.classList.toggle('is-disabled',!enabled);button.classList.toggle('is-stock-soldout',!enabled);button.title=enabled?'':'품절';if(!enabled&&button.classList.contains('is-selected'))button.classList.remove('is-selected')})});if(groups.every(group=>current()[group]))syncMenTotal();else if(!selectionAvailable(current()))zeroTotal()}async function load(){try{const response=await fetch('/api/products/slug/'+slug+'?v='+Date.now(),{cache:'no-store'}),data=await response.json();liveProduct=data;if(Array.isArray(data.variants)&&data.variants.length)liveVariants=data.variants;loaded=true;renderDynamicOptions();applyProduct();applyStock();syncMenTotal()}catch(error){console.warn('product sync failed',error)}}const previousSyncTotal=window.syncTotal;if(typeof previousSyncTotal==='function'){window.syncTotal=function(){previousSyncTotal();if(isMen()&&loaded)syncMenTotal()}}else{window.syncTotal=function(){if(isMen()&&loaded)syncMenTotal()}}document.addEventListener('click',event=>{if(!isMen())return;const optionButton=event.target.closest('.men-option-block .size-button');if(optionButton){event.preventDefault();event.stopImmediatePropagation();if(optionButton.disabled||optionButton.classList.contains('is-stock-soldout')){applyStock();return}const block=optionButton.closest('.option-block'),wasSelected=optionButton.classList.contains('is-selected');block?.querySelectorAll('.size-button').forEach(button=>button.classList.toggle('is-selected',!wasSelected&&button===optionButton));applyStock();syncMenTotal();return}if(event.target.closest('.add-cart,.guest-buy')){const selection=current();if((loaded&&!groups.every(group=>selection[group]))||(loaded&&!selectionAvailable(selection))){event.preventDefault();event.stopImmediatePropagation();alert('선택한 옵션은 품절입니다. 다른 옵션을 선택해주세요.');applyStock()}}},true);addEventListener('hashchange',()=>setTimeout(()=>{if(isMen())load()},120));setTimeout(()=>{if(isMen())load()},180)})();</script><style id="bare-product-stock-style">.men-option-block .size-button.is-stock-soldout{opacity:.28!important;cursor:not-allowed!important;text-decoration:line-through!important;background:#f4f4f4!important;color:#888!important;border-color:#ddd!important}</style>`;

