const money=v=>'₩'+Number(v||0).toLocaleString('ko-KR'),date=v=>v?new Date(v).toLocaleString('ko-KR'):'-',esc=v=>String(v??'').replace(/[&<>"']/g,c=>'&#'+c.charCodeAt(0)+';');
const labels={all:'전체',paid:'결제완료',confirmed:'발주확인',ready:'상품준비중',shipping:'배송중',done:'배송완료',cancel_requested:'취소요청',cancelled:'취소완료',exchange_requested:'교환요청',return_requested:'반품요청'};
