async function api(path,opt={}){const r=await fetch(path,{...opt,headers:{'Content-Type':'application/json',Authorization:'Bearer '+token(),...(opt.headers||{})}});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.message||'요청을 처리하지 못했습니다.');return d}
function products(order){return (order.items||[]).map(i=>i.product_title+(i.option_text?' / '+i.option_text:'')).join(', ')||'-'}
function rowStatus(order){return labels[order.fulfillment_status]||order.fulfillment_status||'-'}
