function renderTabs(){const counts=orders.reduce((m,o)=>{m[o.fulfillment_status]=(m[o.fulfillment_status]||0)+1;return m},{});$('#status-tabs').innerHTML=tabs.map(([key,label])=>'<button class="'+(active===key?'is-active':'')+'" data-filter="'+key+'" type="button">'+label+' '+(key==='all'?orders.length:key==='issue'?['cancel_requested','cancelled','exchange_requested','return_requested'].reduce((s,k)=>s+(counts[k]||0),0):(counts[key]||0))+'</button>').join('')}
function renderMetrics(m={}){$('#m-orders').textContent=m.orders??orders.length;$('#m-today').textContent=m.todayOrders??0;$('#m-sales').textContent=money(m.paidAmount||orders.reduce((s,o)=>s+Number(o.amount||0),0));$('#m-action').textContent=m.needAction??orders.filter(o=>['paid','confirmed','ready'].includes(o.fulfillment_status)).length;$('#m-shipping').textContent=m.shipping??orders.filter(o=>o.fulfillment_status==='shipping').length}
function render(){renderTabs();renderMetrics();const rows=filtered();$('#body').innerHTML=rows.length?rows.map(o=>'<tr data-order="'+esc(o.order_id)+'"><td>'+date(o.created_at)+'</td><td><strong>'+esc(o.order_id)+'</strong></td><td>'+esc(o.buyer_name||'-')+'<br><span class="muted">'+esc(o.phone||'')+'</span></td><td>'+esc(products(o))+'</td><td>'+money(o.amount)+'</td><td>'+esc(o.payment_method||'-')+'</td><td><span class="badge '+esc(o.fulfillment_status||'')+'">'+esc(rowStatus(o))+'</span></td><td>'+esc([o.tracking_company,o.tracking_number].filter(Boolean).join(' ')||'-')+'</td></tr>').join(''):'<tr><td colspan="8" class="empty">표시할 주문이 없습니다.</td></tr>'}
async function load(){status('주문을 불러오는 중입니다.');const data=await api('/api/admin/summary');orders=data.orders||[];renderMetrics(data.metrics||{});render();status((session.user.email||'관리자')+' 계정으로 로그인했습니다.')}
function openOrder(order){$('#drawer-title').textContent='주문 상세';$('#drawer').classList.add('is-open');$('#drawer-body').innerHTML='<div class="grid"><span>주문번호</span><strong>'+esc(order.order_id)+'</strong><span>주문자</span><strong>'+esc(order.buyer_name||'-')+'</strong><span>연락처</span><strong>'+esc(order.phone||'-')+'</strong><span>이메일</span><strong>'+esc(order.email||'-')+'</strong><span>주소</span><strong>'+esc(order.address||'-')+'</strong><span>배송메모</span><strong>'+esc(order.memo||'-')+'</strong><span>결제금액</span><strong>'+money(order.amount)+'</strong><span>결제수단</span><strong>'+esc(order.payment_method||'-')+'</strong><span>현재상태</span><strong>'+esc(rowStatus(order))+'</strong></div><h3>상품</h3><div class="items">'+(order.items||[]).map(i=>'<article class="item"><img src="'+esc(i.image_url||'')+'" alt=""><div><p>'+esc(i.product_title)+'</p><small>'+esc(i.option_text||'')+'</small></div><strong>'+money(i.price)+'</strong></article>').join('')+'</div><div class="quick"><button data-status="confirmed">발주확인</button><button data-status="ready">상품준비중</button><button data-status="shipping" class="primary">배송중</button><button data-status="done">배송완료</button><button data-status="cancelled">취소완료</button><button data-status="return_requested">반품요청</button></div><div class="form-grid"><label class="field"><span>주문상태</span><select id="detail-status">'+Object.entries(labels).filter(([k])=>k!=='all').map(([k,v])=>'<option value="'+k+'">'+v+'</option>').join('')+'</select></label><label class="field"><span>택배사</span><input id="tracking-company" value="'+esc(order.tracking_company||'')+'" placeholder="예: CJ대한통운"></label><label class="field"><span>송장번호</span><input id="tracking-number" value="'+esc(order.tracking_number||'')+'" placeholder="송장번호"></label><label class="field"><span>취소/CS 사유</span><input id="cancel-reason" value="'+esc(order.cancel_reason||'')+'" placeholder="선택 입력"></label></div><label class="field"><span>관리자 메모</span><textarea id="customer-note">'+esc(order.customer_note||'')+'</textarea></label><div class="save-row"><button class="btn secondary" id="copy-address" type="button">배송지 복사</button><button class="btn" id="save-order" type="button">저장</button></div><p class="notice">송장번호를 입력하고 배송중으로 저장하면 운영상태가 배송중으로 변경됩니다.</p>';$('#detail-status').value=order.fulfillment_status||'paid';$('#drawer-body').querySelectorAll('[data-status]').forEach(b=>b.addEventListener('click',()=>{$('#detail-status').value=b.dataset.status}));$('#copy-address').addEventListener('click',()=>navigator.clipboard?.writeText([order.buyer_name,order.phone,order.address].filter(Boolean).join(' / ')));$('#save-order').addEventListener('click',async()=>{await saveOrder(order.order_id);})}
async function saveOrder(orderId){const body={fulfillment_status:$('#detail-status').value,tracking_company:$('#tracking-company').value,tracking_number:$('#tracking-number').value,customer_note:$('#customer-note').value,cancel_reason:$('#cancel-reason').value};await api('/api/admin/orders/'+encodeURIComponent(orderId),{method:'PATCH',body:JSON.stringify(body)});$('#drawer').classList.remove('is-open');await load()}
