function productSlug(value){
  return String(value||'product').trim().toLowerCase()
    .normalize('NFKD').replace(/[^\w\s-]/g,'').replace(/[\s_]+/g,'-').replace(/^-+|-+$/g,'')
    || ('product-'+Date.now());
}
function normalizeProductVariants(input=[]){
  return (Array.isArray(input)?input:[]).slice(0,120).map((item,index)=>{
    const color=String(item.color||'').trim();
    const back=String(item.back||'').trim();
    const size=String(item.size||'').trim();
    const stock=Math.max(0,Number(String(item.stock??0).replace(/[^0-9]/g,''))||0);
    const active=item.active!==false;
    const id=String(item.id||[color,back,size].filter(Boolean).join('|')||('variant-'+index)).trim();
    return {
      id,
      color,
      back,
      size,
      sku:String(item.sku||'').trim(),
      stock,
      soldout:active&&stock<=0?true:Boolean(item.soldout),
      active
    };
  }).filter(item=>item.color||item.back||item.size);
}
async function readProductBody(request){
  const body=await request.json().catch(()=>({}));
  const name=String(body.name||'').trim();
  if(!name)throw new Error('상품명을 입력해주세요.');
  const price=Math.max(0,Number(String(body.price||0).replace(/[^0-9]/g,''))||0);
  const compare_price=Math.max(0,Number(String(body.compare_price||body.comparePrice||0).replace(/[^0-9]/g,''))||0);
  const status=String(body.status||'draft');
  if(!['published','draft','soldout'].includes(status))throw new Error('판매 상태를 확인해주세요.');
  const variants=normalizeProductVariants(body.variants);
  const activeVariants=variants.filter(item=>item.active!==false);
  const variantStock=activeVariants.reduce((sum,item)=>sum+Number(item.stock||0),0);
  const rowStatus=status==='published'&&activeVariants.length&&activeVariants.every(item=>item.soldout||Number(item.stock||0)<=0)?'soldout':status;
  const slug=productSlug(body.slug||name);
  return {
    slug,
    sku:String(body.sku||'').trim()||null,
    name,
    category:String(body.category||'TOP').trim()||'TOP',
    status:rowStatus,
    price,
    compare_price,
    stock:variants.length?variantStock:(Number(body.stock||0)||0),
    description:String(body.description||'').trim(),
    sizes:Array.isArray(body.sizes)?body.sizes.map(String):[],
    colors:Array.isArray(body.colors)?body.colors.map(String):[],
    tags:Array.isArray(body.tags)?body.tags.map(String).filter(Boolean):[],
    images:Array.isArray(body.images)?body.images:[],
    variants,
    sort_order:Number(body.sort_order||0)||0,
    published_at:rowStatus==='published'?new Date().toISOString():null,
    updated_at:new Date().toISOString()
  };
}
function seedImage(url,gap=24){
  return {url,path:null,name:String(url).split('/').pop()?.split('?')[0]||'image',gap};
}
