const bareAdminApiWithManualCreate=adminApi;
adminApi=async function(request,env,url){
  if(url.pathname==='/api/admin/orders'&&request.method==='POST'){
    try{
      await requireAdmin(request,env);
      const body=await request.json().catch(()=>({}));
      const orderId=String(body.order_id||body.orderId||'').trim();
      if(!orderId)return jsonResponse({message:'order_id is required.'},400);
      const exists=await supabaseRest(env,'orders?select=order_id&order_id=eq.'+encodeURIComponent(orderId)+'&limit=1');
      if(Array.isArray(exists)&&exists.length)return jsonResponse({message:'Order already exists.',order_id:orderId},409);
      const amount=Math.max(0,Number(body.amount||0)||0);
      if(!amount)return jsonResponse({message:'amount is required.'},400);
      const createdAt=body.created_at?new Date(body.created_at):new Date();
      const paidAt=Number.isNaN(createdAt.getTime())?new Date():createdAt;
      const rawPayment={
        source:'manual_admin',
        note:String(body.note||'Manual order recovery').slice(0,500),
        payment_key:body.payment_key||null,
        created_at:paidAt.toISOString()
      };
      const orderRows=await supabaseRest(env,'orders',{method:'POST',body:JSON.stringify({
        order_id:orderId,
        payment_key:String(body.payment_key||'').trim()||null,
        buyer_name:String(body.buyer_name||body.buyer||'').trim(),
        phone:String(body.phone||'').replace(/[^0-9]/g,''),
        email:String(body.email||'').trim(),
        address:String(body.address||'').trim(),
        memo:String(body.memo||'').trim(),
        amount,
        payment_method:String(body.payment_method||'KAKAOPAY').trim(),
        payment_status:'paid',
        fulfillment_status:String(body.fulfillment_status||'paid').trim()||'paid',
        raw_payment:rawPayment,
        created_at:paidAt.toISOString(),
        updated_at:new Date().toISOString()
      })});
      const items=cleanOrderItems(Array.isArray(body.items)?body.items:[]);
      if(items.length)await supabaseRest(env,'order_items',{method:'POST',body:JSON.stringify(items.map(item=>({...item,order_id:orderId})))});
      const stockUpdate=await decrementVariantStocks(env,items);
      return jsonResponse({ok:true,order:orderRows?.[0]||null,items,stockUpdate});
    }catch(error){
      return jsonResponse({message:error.message||'Manual order creation failed.'},403);
    }
  }
  return bareAdminApiWithManualCreate(request,env,url);
};

